#!/usr/bin/env python3
import argparse
import random
import sys

ADJECTIVES = [
    "Agile", "Brave", "Cosmic", "Daring", "Epic", "Funky", "Groovy",
    "Hyper", "Infinite", "Jolly", "Kinetic", "Luminous", "Mystic",
    "Neon", "Optimistic", "Phantom", "Quantum", "Radical", "Solar",
    "Turbo", "Ultra", "Vivid", "Wild", "Xtreme", "Youthful", "Zealous"
]

NOUNS = [
    "Albatross", "Beacon", "Cyclone", "Dragon", "Engine", "Falcon",
    "Galaxy", "Hacker", "Inferno", "Jester", "Knight", "Lion",
    "Matrix", "Ninja", "Oracle", "Pirate", "Quartz", "Rocket",
    "Samurai", "Titan", "Unicorn", "Vortex", "Warden", "Xenon",
    "Yeti", "Zeppelin"
]

def generate_project_name():
    adjective = random.choice(ADJECTIVES)
    noun = random.choice(NOUNS)
    return f"{adjective} {noun}"

def main():
    parser = argparse.ArgumentParser(
        description="Generate fun and memorable random project names for your software projects!"
    )
    parser.add_argument(
        "-n", "--number", type=int, default=1,
        help="Number of project names to generate (default: 1)"
    )
    parser.add_argument(
        "--seed", type=int, default=None,
        help="Seed for random generator (for reproducible results)"
    )
    args = parser.parse_args()

    if args.seed is not None:
        random.seed(args.seed)

    for _ in range(args.number):
        print(generate_project_name())

if __name__ == "__main__":
    try:
        main()
    except KeyboardInterrupt:
        sys.exit("\nOperation cancelled by user.")
